const rawSearchTerm = String($('Workflow Trigger').first().json.search_term || '').trim();
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const normalizedSearchTerm = norm(rawSearchTerm).replace(/[^a-z0-9\s-]/g, ' ').replace(/\s+/g, ' ').trim();
const searchWords = normalizedSearchTerm.split(/\s+/).filter((word) => word.length > 1);
const candidateTokens = Array.from(new Set(searchWords)).slice(0, 10);

return [{
  json: {
    raw_search_term: rawSearchTerm,
    normalized_search_term: normalizedSearchTerm,
    candidate_tokens: candidateTokens,
    has_candidate_tokens: candidateTokens.length > 0,
  }
}];

// Busca fuzzy com pré-filtro por search_tokens.
// Mantém fallback legado enquanto a base é retroalimentada com os novos campos.

const inputItems = $input.all().map((item) => item.json || {});
const docs = [];
for (const entry of inputItems) {
  if (entry.document) {
    docs.push(entry.document);
    continue;
  }
  if (Array.isArray(entry.documents)) {
    docs.push(...entry.documents);
  }
}

const searchTerm = $('Workflow Trigger').first().json.search_term || '';
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const searchWords = norm(searchTerm).split(/\s+/).filter((w) => w.length > 1);

const sizeWords = new Set(['pp', 'p', 'm', 'g', 'gg', 'xg', 'xxg', 'xs', 's', 'l', 'xl', 'xxl']);
const isNumericSize = (w) => /^\d{1,3}$/.test(w);

function parseValue(val) {
  if (!val) return null;
  if (val.stringValue !== undefined) return val.stringValue;
  if (val.integerValue !== undefined) return Number(val.integerValue);
  if (val.doubleValue !== undefined) return Number(val.doubleValue);
  if (val.booleanValue !== undefined) return val.booleanValue;
  if (val.timestampValue !== undefined) return val.timestampValue;
  if (val.nullValue !== undefined) return null;
  if (val.arrayValue) return (val.arrayValue.values || []).map((value) => parseValue(value));
  if (val.mapValue) {
    const obj = {};
    for (const [key, value] of Object.entries(val.mapValue.fields || {})) obj[key] = parseValue(value);
    return obj;
  }
  return JSON.stringify(val);
}

const products = docs.map((doc) => {
  const product = { sku: doc.name?.split('/').pop() || '' };
  for (const [key, val] of Object.entries(doc.fields || {})) {
    product[key] = parseValue(val);
  }

  const imageUrls = Array.isArray(product.image_urls)
    ? product.image_urls.filter(Boolean)
    : product.image_url
      ? [product.image_url]
      : [];

  return {
    ...product,
    image_urls: imageUrls,
    image_url: imageUrls[0] || product.image_url || '',
    ai_instructions: product.ai_instructions || '',
  };
}).filter((product) => product.is_active !== false);

if (products.length === 0) {
  return [{ json: { found: false, message: 'Nenhum produto encontrado.' } }];
}

if (searchWords.length === 0) {
  const available = products.filter((product) => (product.stock || 0) > 0);
  return available.slice(0, 15).map((product) => ({
    json: {
      found: true,
      name: product.name,
      color: product.color || '',
      size: product.size || '',
      price: product.price,
      stock: product.stock,
      description: product.description || '',
      category: product.category || '',
      ai_instructions: product.ai_instructions || '',
      image_url: product.image_url || '',
      image_urls: product.image_urls || [],
    }
  }));
}

const productWords = [];
let searchedSize = null;
const colorWords = [];

const knownColors = ['preto', 'branco', 'azul', 'vermelho', 'verde', 'amarelo', 'rosa', 'roxo', 'laranja', 'marrom', 'cinza', 'bege', 'dourado', 'prata', 'nude', 'caramelo', 'vinho', 'bordo', 'coral', 'lilas', 'turquesa', 'creme', 'grafite', 'off-white', 'offwhite'];

for (const word of searchWords) {
  if (sizeWords.has(word) || isNumericSize(word)) {
    searchedSize = word;
  } else if (knownColors.includes(word)) {
    colorWords.push(word);
  } else {
    productWords.push(word);
  }
}

function searchable(product) {
  const tagsStr = Array.isArray(product.tags) ? product.tags.join(' ') : (product.tags || '');
  const indexed = Array.isArray(product.search_tokens) ? product.search_tokens.join(' ') : (product.search_text || '');
  return norm([product.name || '', product.description || '', product.category || '', tagsStr, indexed].join(' '));
}

const scored = products.map((product) => {
  const text = searchable(product);
  const nameNorm = norm(product.name);
  let score = 0;

  for (const word of productWords) {
    if (text.includes(word)) score += 10;
    for (const textWord of text.split(/\s+/)) {
      if (textWord.startsWith(word) || word.startsWith(textWord)) score += 3;
    }
  }
  if (productWords.length > 0 && nameNorm.includes(productWords.join(' '))) score += 25;
  if (norm(product.category) === productWords.join(' ')) score += 15;
  if (Array.isArray(product.tags) && product.tags.some((tag) => productWords.some((productWord) => norm(tag).includes(productWord)))) score += 10;

  let colorMatch = colorWords.length === 0 ? null : false;
  if (colorWords.length > 0 && product.color) {
    if (colorWords.some((color) => norm(product.color).includes(color))) {
      colorMatch = true;
      score += 15;
    }
  }

  let sizeMatch = searchedSize === null ? null : false;
  if (searchedSize && product.size !== undefined && product.size !== null) {
    if (norm(String(product.size)) === searchedSize) {
      sizeMatch = true;
      score += 15;
    }
  }

  return {
    sku: product.sku,
    name: product.name,
    color: product.color || '',
    size: product.size !== undefined ? product.size : '',
    price: product.price,
    stock: product.stock || 0,
    description: product.description || '',
    category: product.category || '',
    ai_instructions: product.ai_instructions || '',
    image_url: product.image_url || '',
    image_urls: product.image_urls || [],
    _score: score,
    _colorMatch: colorMatch,
    _sizeMatch: sizeMatch,
    _inStock: (product.stock || 0) > 0,
  };
});

const relevant = scored.filter((product) => product._score > 0).sort((a, b) => b._score - a._score);

if (relevant.length === 0) {
  return [{ json: { found: false, message: 'Nenhum produto encontrado para: ' + searchTerm } }];
}

const exact = relevant.filter((product) =>
  product._inStock &&
  (product._colorMatch === null || product._colorMatch === true) &&
  (product._sizeMatch === null || product._sizeMatch === true)
);

const sameProductDiffColor = relevant.filter((product) =>
  product._inStock &&
  product._colorMatch === false &&
  (product._sizeMatch === null || product._sizeMatch === true)
);

const sameProductDiffSize = relevant.filter((product) =>
  product._inStock &&
  (product._colorMatch === null || product._colorMatch === true) &&
  product._sizeMatch === false
);

const outOfStock = relevant.filter((product) =>
  !product._inStock &&
  (product._colorMatch === null || product._colorMatch === true) &&
  (product._sizeMatch === null || product._sizeMatch === true)
);

const stripInternal = ({ _score, _colorMatch, _sizeMatch, _inStock, ...product }) => product;
const result = { found: true };

if (exact.length > 0) {
  result.exact_matches = exact.slice(0, 5).map(stripInternal);
}
if (sameProductDiffColor.length > 0) {
  result.alternative_colors = sameProductDiffColor.slice(0, 5).map(stripInternal);
}
if (sameProductDiffSize.length > 0) {
  result.alternative_sizes = sameProductDiffSize.slice(0, 5).map(stripInternal);
}
if (outOfStock.length > 0) {
  result.out_of_stock = outOfStock.slice(0, 3).map(stripInternal);
}

if (!result.exact_matches && !result.alternative_colors && !result.alternative_sizes) {
  result.found = false;
  result.message = 'Produto não encontrado com essas especificações.';
  if (outOfStock.length > 0) result.message += ' Estava no catálogo mas zerou o estoque.';
}

return [{ json: result }];
